        is_extract_failed = True
        match_count = 0
        llm_matched_index = -1
        is_completed = False
        reply = ""

    if is_extract_failed:
        match_count = 0
        llm_matched_index = -1
        is_completed = False
        reply = ""

    if match_count == 1 and llm_matched_index < 0:
        if current_state == "confirming" and current_matched_index >= 0:
            llm_matched_index = current_matched_index
        else:
            match_count = 0

    if match_count >= 2 and llm_matched_index >= 0:
        llm_matched_index = -1
        is_completed = False

    if is_completed and llm_matched_index < 0:
        if current_state == "confirming" and current_matched_index >= 0:
            llm_matched_index = current_matched_index
            match_count = 1
        else:
            is_completed = False

    if llm_matched_index >= 0 and match_count <= 0:
        match_count = 1

    if current_state == "matching" and llm_matched_index < 0 and match_count == 0 and not is_completed and not is_extract_failed:
        precise_matched_index = _find_precise_unique_match(current_input, address_list)
        if precise_matched_index >= 0:
            llm_matched_index = precise_matched_index
            match_count = 1
            reply = ""

    next_last_unmatched_address = ""
    next_similar_no_match_count = 0

    current_looks_like_address = _looks_like_address(current_input)
    current_is_layer_missing = _is_layer_missing(current_input)
    current_has_effective_address = _has_effective_address(current_input)
    current_address_level = _address_detail_level(current_input)
    should_echo_partial_address = bool(
        current_input
        and current_looks_like_address
        and _needs_specific_place_followup(current_input)
        and not (not prev_unmatched and current_is_layer_missing and not _has_any_core_region_overlap(current_input, address_list))
    )

    custom_followup_reply = ""
    custom_recorded_address = ""
    if current_state == "matching" and llm_matched_index < 0 and match_count == 0 and not is_completed:
        custom_followup_reply, custom_recorded_address = _build_precise_followup(
            prev_unmatched,
            current_input,
            address_list
        )
        if recorded_address_from_reply:
            recorded_address_from_reply, reply = _prefer_recorded_followup(
                recorded_address_from_reply,
                reply,
                custom_recorded_address,
                custom_followup_reply,
                prev_unmatched,
                current_input
            )

    should_track_unmatched = (
        current_state == "matching"
        and llm_matched_index < 0
        and match_count == 0
        and not is_completed
        and bool(current_input)
        and (current_looks_like_address or bool(recorded_address_from_reply) or bool(custom_recorded_address))
    )

    if should_track_unmatched:
        if prev_unmatched and _is_similar(current_input, prev_unmatched) and not _is_extension_of_previous(current_input, prev_unmatched):
            is_extract_failed = True
            match_count = 0
            llm_matched_index = -1
            is_completed = False
            reply = ""
            next_last_unmatched_address = ""
            next_similar_no_match_count = 0
        else:
            next_last_unmatched_address = (
                recorded_address_from_reply
                or custom_recorded_address
                or current_input
            )
            next_similar_no_match_count = 1
    else:
        if llm_matched_index >= 0 or is_completed:
            next_last_unmatched_address = ""
            next_similar_no_match_count = 0
        else:
            next_last_unmatched_address = prev_unmatched
            next_similar_no_match_count = prev_repeat_count

    REPLY_LAYER = "好的，请您再说一下具体的小区或村镇名称。"
    REPLY_DETAIL = "请您提供详细的地址信息"
    REPLY_CORRECT = "请您提供正确完整的地址信息"

    reply_alias_map = {
        "好的，请您再说一下具体的小区或村镇名称": REPLY_LAYER,
        "请您提供详细的地址信息。": REPLY_DETAIL,
        "请您提供详细地址信息": REPLY_DETAIL,
        "请您提供正确的地址信息": REPLY_CORRECT,
        "请您提供正确的地址信息。": REPLY_CORRECT,
        "请您提供正确完整的地址信息。": REPLY_CORRECT
    }
    reply = reply_alias_map.get(reply, reply)

    forbidden_matching_replies = {
        "好的，请您再重新说一下报修宽带所在小区或村镇名称。",
        "好的，请您再重新说一下报修宽带所在小区或村镇名称"
    }
    if reply in forbidden_matching_replies:
        if current_state == "confirming":
            reply = REPLY_DETAIL
        elif current_state == "matching":
            reply = ""

    if current_state == "matching" and llm_matched_index < 0 and match_count == 0 and not is_completed:
        if is_extract_failed:
            reply = ""
        elif recorded_address_from_reply:
            pass
        elif custom_followup_reply:
            reply = custom_followup_reply
        elif (
            current_looks_like_address
            and _has_building_or_room(current_input)
            and not _has_place_anchor(current_input)
            and not prev_unmatched
        ):
            reply = f"我记录的地址信息是：{current_input}，请您再说一下具体的小区或村镇名称。"
        elif should_echo_partial_address:
            reply = f"\u6211\u8bb0\u5f55\u7684\u5730\u5740\u4fe1\u606f\u662f\uff1a{current_input}\uff0c\u8bf7\u60a8\u518d\u8bf4\u4e00\u4e0b\u5177\u4f53\u7684\u5c0f\u533a\u6216\u6751\u9547\u540d\u79f0\u3002"
        elif reply == REPLY_LAYER or _is_exact_layer_reply(reply):
            if not prev_unmatched and current_is_layer_missing and not _has_any_core_region_overlap(current_input, address_list):
                reply = REPLY_CORRECT
            elif current_address_level >= 5:
                reply = REPLY_CORRECT
        elif reply in {REPLY_DETAIL, REPLY_CORRECT}:
            pass
        else:
            if not current_input:
                reply = REPLY_DETAIL
            elif current_is_layer_missing:
                reply = REPLY_LAYER
            elif current_looks_like_address:
                reply = REPLY_CORRECT
            else:
                reply = REPLY_DETAIL

    if current_state == "confirming" and current_matched_index >= 0:
        if not is_completed and match_count <= 0 and llm_matched_index < 0 and not reply and not is_extract_failed:
            llm_matched_index = current_matched_index
            match_count = 1

    if is_completed or is_extract_failed or (match_count == 1 and llm_matched_index >= 0):
        reply = ""

    llm_result["match_count"] = match_count
    llm_result["matched_index"] = llm_matched_index
    llm_result["is_completed"] = is_completed
    llm_result["is_extract_failed"] = is_extract_failed
    llm_result["reply"] = reply

    return {
        "llm_result": llm_result,
        "next_last_unmatched_address": next_last_unmatched_address,
        "next_similar_no_match_count": next_similar_no_match_count
    }

def main(
    data: dict,
    llm_result: dict,
    user_spoken_address: str = "",
    clean_user_input: str = "",
    last_unmatched_address: str = ""
) -> dict:
    import re

    match_failed = bool(data.get("match_failed", False))
    is_completed = bool(data.get("is_completed", False))
    state = str(data.get("state") or "matching").strip()

    try:
        matched_index = int(data.get("matched_index") if data.get("matched_index") is not None else -1)
    except (ValueError, TypeError):
        matched_index = -1

    matched_account = str(data.get("matched_account") or "").strip()

    if not isinstance(llm_result, dict):
        llm_result = {}

    llm_reply = str(llm_result.get("reply") or "").strip()

    try:
        match_count = int(llm_result.get("match_count") if llm_result.get("match_count") is not None else -1)
    except (ValueError, TypeError):
        match_count = -1

    MATCH_FAILED_REPLY_SAME = "抱歉你提供的地址匹配不上，请重新提供一下所在小区或者村庄"
    SHORT_MATCH_FAILED_REPLY = "抱歉您提供的地址匹配不上。"
    CONFIRM_REPLY_TEMPLATE = "请问您说的是{address}吗？"
    CUSTOM_PREFIX = "我记录的地址信息是："

    def _to_str(value) -> str:
        return str(value or "").strip()

    def _normalize_cn_digits(text: str) -> str:
        text = _to_str(text)
        if not text or text.isdigit():
            return text

        digit_map = {
            "零": 0, "一": 1, "二": 2, "两": 2, "三": 3, "四": 4,
            "五": 5, "六": 6, "七": 7, "八": 8, "九": 9
        }
        unit_map = {"十": 10, "百": 100, "千": 1000}

        total = 0
        current = 0
        has_cn = False
        for ch in text:
            if ch in digit_map:
                current = digit_map[ch]
                has_cn = True
            elif ch in unit_map:
                has_cn = True
                if current == 0:
                    current = 1
                total += current * unit_map[ch]
                current = 0
            else:
                return text

        if not has_cn:
            return text
        total += current
        return str(total)

    def _normalize_short_address(text: str) -> str:
        text = _to_str(text)
        if not text:
            return ""

        def _replace(match):
            return f"{_normalize_cn_digits(match.group(1))}{match.group(2)}"

        return re.sub(r"([\u4e00\u4e8c\u4e09\u56db\u4e94\u516d\u4e03\u516b\u4e5d\u5341\u767e\u96f6\u4e24\d]+)(\u680b|\u5e62|\u5ea7|\u53f7\u697c|\u697c)", _replace, text)

    def _looks_like_place_anchor(text: str) -> bool:
        text = _to_str(text)
        if not text:
            return False
        return bool(re.search("(\u5c0f\u533a|\u82b1\u56ed|\u516c\u5bd3|\u5927\u53a6|\u82d1|\u6751|\u9547|\u4e61|\u8857\u9053|\u8def|\u5927\u9053|\u5df7|\u80e1\u540c|\u8857(?!\u9053))", text))

    def _has_building_or_room(text: str) -> bool:
        text = _to_str(text)
        if not text:
            return False
        return bool(re.search(r"((?:\d+|[\u4e00\u4e8c\u4e09\u56db\u4e94\u516d\u4e03\u516b\u4e5d\u5341\u767e\u96f6\u4e24]+)(?:\u680b|\u5e62|\u5ea7|\u53f7\u697c|\u697c)|\d+\u5355\u5143|\d+\u5ba4|(?<!\d)\d{3,6}(?!\d))", text))

    def _build_short_confirm_address() -> str:
        spoken = _to_str(user_spoken_address)
        clean = _to_str(clean_user_input)
        prev = _to_str(last_unmatched_address)

        if clean and prev and _looks_like_place_anchor(clean) and _has_building_or_room(prev):
            spoken = f"{clean}{prev}"
        elif not spoken and clean:
            spoken = clean

        spoken = _normalize_short_address(spoken)
        return spoken or matched_account

    reply = ""

    if is_completed:
        reply = "好的，请稍候"
    elif llm_reply.startswith(CUSTOM_PREFIX):
        reply = llm_reply
    elif match_failed:
        reply = SHORT_MATCH_FAILED_REPLY
    elif state == "confirming" and matched_index >= 0:
        confirm_address = _build_short_confirm_address() if matched_account else ""
        reply = CONFIRM_REPLY_TEMPLATE.format(address=confirm_address) if confirm_address else MATCH_FAILED_REPLY_SAME
    elif match_count == 0:
        reply = llm_reply if llm_reply else MATCH_FAILED_REPLY_SAME
    else:
        reply = llm_reply

    if not (match_failed or is_completed) and not reply:
        reply = MATCH_FAILED_REPLY_SAME

    return {
        "matched_account": matched_account,
        "matched_index": matched_index,
        "is_completed": is_completed,
        "match_failed": match_failed,
        "reply": reply,
        "state": state
    }

